# ---- 3. Data Manipulations ----
generation_credit_summary <- DATA %>% 
  mutate(Generation = if_else(Age <= 29, "Gen Z", if_else(Age <= 45, "Millennial", "Other"))) %>%
  filter(Generation == "Gen Z" | Generation == "Millennial") %>%
  select(Generation, Credit_amount, Duration, Risk) %>%
  mutate(installment = monthly_payment(Credit_amount, Duration)) %>%
  group_by(Generation) %>%
  summarize(Avg_Credit_amount = mean(Credit_amount, na.rm = T), Avg_Duration = mean(Duration, na.rm = T), Avg_installment = mean(installment), Bad_Risk_Rate = mean(Risk == "bad") * 100, Total_count = n())

df.generation_credit_summary <- data.frame(generation_credit_summary)

